-- Multi-location support for merchants
-- Each merchant can have multiple physical locations (branches/stores)

create table public.merchant_locations (
  id uuid primary key default uuid_generate_v4(),
  merchant_id uuid references merchants(id) on delete cascade not null,
  name text not null,
  address text,
  latitude double precision,
  longitude double precision,
  geog geography(Point, 4326),
  is_active boolean default true,
  created_at timestamptz default now()
);

-- Row-level security
alter table public.merchant_locations enable row level security;

create policy "Locations: merchant owner"
  on public.merchant_locations
  for all
  using (merchant_id in (select id from merchants where user_id = auth.uid()));

-- Update QR codes to optionally link to a location
alter table public.qr_codes add column if not exists location_id uuid references merchant_locations(id);

-- Trigger function to auto-compute geography from lat/lng
create or replace function update_location_geog()
returns trigger as $$
begin
  if new.latitude is not null and new.longitude is not null then
    new.geog = st_point(new.longitude, new.latitude)::geography;
  end if;
  return new;
end;
$$ language plpgsql;

create trigger location_geog_trigger
  before insert or update on merchant_locations
  for each row execute function update_location_geog();

-- Spatial index for proximity queries on locations
create index idx_merchant_locations_geog on merchant_locations using gist(geog);

-- Standard indexes
create index idx_merchant_locations_merchant on merchant_locations(merchant_id);

'use client';

import { useEffect, useState, useCallback } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';

interface Location {
  id: string;
  name: string;
  address: string | null;
  latitude: number | null;
  longitude: number | null;
  is_active: boolean;
  created_at: string;
}

export default function LocationsPage() {
  const supabase = createClient();
  const [locations, setLocations] = useState<Location[]>([]);
  const [merchantId, setMerchantId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Form state
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [latitude, setLatitude] = useState('');
  const [longitude, setLongitude] = useState('');

  const fetchLocations = useCallback(async (mId: string) => {
    const { data } = await supabase
      .from('merchant_locations')
      .select('*')
      .eq('merchant_id', mId)
      .order('created_at', { ascending: false });
    setLocations(data ?? []);
  }, [supabase]);

  useEffect(() => {
    async function init() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const { data: merchant } = await supabase
        .from('merchants')
        .select('id')
        .eq('user_id', user.id)
        .single();
      if (!merchant) return;
      setMerchantId(merchant.id);
      await fetchLocations(merchant.id);
      setLoading(false);
    }
    init();
  }, [supabase, fetchLocations]);

  async function handleAdd() {
    if (!merchantId || !name.trim()) return;
    setSaving(true);
    const { error } = await supabase.from('merchant_locations').insert({
      merchant_id: merchantId,
      name: name.trim(),
      address: address.trim() || null,
      latitude: latitude ? parseFloat(latitude) : null,
      longitude: longitude ? parseFloat(longitude) : null,
    });
    if (error) {
      console.error('Failed to add location:', error.message);
    } else {
      setName('');
      setAddress('');
      setLatitude('');
      setLongitude('');
      await fetchLocations(merchantId);
    }
    setSaving(false);
  }

  async function handleToggleActive(location: Location) {
    const { error } = await supabase
      .from('merchant_locations')
      .update({ is_active: !location.is_active })
      .eq('id', location.id);
    if (error) {
      console.error('Failed to toggle location:', error.message);
    } else if (merchantId) {
      await fetchLocations(merchantId);
    }
  }

  async function handleDelete(locationId: string) {
    if (!confirm('Are you sure you want to delete this location?')) return;
    const { error } = await supabase
      .from('merchant_locations')
      .delete()
      .eq('id', locationId);
    if (error) {
      console.error('Failed to delete location:', error.message);
    } else if (merchantId) {
      await fetchLocations(merchantId);
    }
  }

  if (loading) {
    return <p className="text-gray-500">Loading locations...</p>;
  }

  return (
    <div>
      <h2 className="text-2xl font-bold mb-6">Locations</h2>

      <div className="grid gap-6 lg:grid-cols-2">
        {/* Add Location Form */}
        <Card>
          <CardHeader>
            <CardTitle>Add Location</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div>
                <Label htmlFor="loc-name">Name *</Label>
                <Input
                  id="loc-name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="e.g. Downtown Branch"
                />
              </div>
              <div>
                <Label htmlFor="loc-address">Address</Label>
                <Input
                  id="loc-address"
                  value={address}
                  onChange={(e) => setAddress(e.target.value)}
                  placeholder="e.g. 123 Main St, City"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label htmlFor="loc-lat">Latitude</Label>
                  <Input
                    id="loc-lat"
                    type="number"
                    step="any"
                    value={latitude}
                    onChange={(e) => setLatitude(e.target.value)}
                    placeholder="48.8566"
                  />
                </div>
                <div>
                  <Label htmlFor="loc-lng">Longitude</Label>
                  <Input
                    id="loc-lng"
                    type="number"
                    step="any"
                    value={longitude}
                    onChange={(e) => setLongitude(e.target.value)}
                    placeholder="2.3522"
                  />
                </div>
              </div>
              <Button
                onClick={handleAdd}
                disabled={saving || !name.trim()}
              >
                {saving ? 'Adding...' : 'Add Location'}
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Locations List */}
        <div>
          <h3 className="font-semibold mb-3">
            Your Locations ({locations.length})
          </h3>
          {!locations.length ? (
            <p className="text-gray-500">
              No locations yet. Add your first branch or store.
            </p>
          ) : (
            <div className="space-y-3">
              {locations.map((loc) => (
                <Card key={loc.id}>
                  <CardContent className="flex items-center justify-between py-4">
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium truncate">{loc.name}</p>
                        <Badge variant={loc.is_active ? 'default' : 'secondary'}>
                          {loc.is_active ? 'Active' : 'Inactive'}
                        </Badge>
                      </div>
                      {loc.address && (
                        <p className="text-sm text-gray-500 truncate">
                          {loc.address}
                        </p>
                      )}
                      {loc.latitude != null && loc.longitude != null && (
                        <p className="text-xs text-gray-400">
                          {loc.latitude.toFixed(4)}, {loc.longitude.toFixed(4)}
                        </p>
                      )}
                    </div>
                    <div className="flex items-center gap-2 ml-3 shrink-0">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleToggleActive(loc)}
                      >
                        {loc.is_active ? 'Deactivate' : 'Activate'}
                      </Button>
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => handleDelete(loc.id)}
                      >
                        Delete
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

